func solve(edges: Array<Array<Int64>>, online: Array<Bool>, k: Int64) -> Int64 {
    let n = online.count
    var adj = [[(Int64, Int64)]](repeating: [], count: n)
    for edge in edges {
        let u = edge[0]
        let v = edge[1]
        let cost = edge[2]
        adj[Int(u)].append((v, cost))
    }

    var maxScore: Int64 = -1
    var visited = [Bool](repeating: false, count: n)

